  // ── Tipos de amortización (lib/amortization + AmortizationHelpModal) ─────────
  'amort.flat.label':     { es: 'Interés y Capital', en: 'Flat Interest', pt: 'Juros e Capital' },
  'amort.flat.short':     { es: 'Cuota fija sobre el monto inicial. La más común para préstamos personales pequeños.', en: 'Fixed installment on the initial amount. The most common for small personal loans.', pt: 'Parcela fixa sobre o valor inicial. A mais comum para empréstimos pessoais pequenos.' },
  'amort.flat.long':      { es: 'El interés se calcula UNA SOLA VEZ sobre el monto inicial del préstamo y se reparte por igual en todas las cuotas. La cuota es siempre la misma. Es el método más simple y popular en préstamos personales informales y comerciales pequeños.', en: 'Interest is calculated ONCE on the initial loan amount and split equally across all installments. The installment is always the same. It is the simplest and most popular method for informal personal and small commercial loans.', pt: 'O juro é calculado UMA ÚNICA VEZ sobre o valor inicial do empréstimo e dividido igualmente em todas as parcelas. A parcela é sempre a mesma. É o método mais simples e popular em empréstimos pessoais informais e comerciais pequenos.' },
  'amort.flat.example':   { es: 'Préstamo RD$ 10,000 al 5% mensual a 12 meses:\n• Interés total: 10,000 × 5% × 12 = RD$ 6,000\n• Total a pagar: 16,000\n• Cuota mensual: 16,000 / 12 = RD$ 1,333.33\n\nLa misma cuota durante los 12 meses.', en: 'Loan RD$ 10,000 at 5% monthly for 12 months:\n• Total interest: 10,000 × 5% × 12 = RD$ 6,000\n• Total to pay: 16,000\n• Monthly installment: 16,000 / 12 = RD$ 1,333.33\n\nThe same installment for all 12 months.', pt: 'Empréstimo RD$ 10.000 a 5% mensal em 12 meses:\n• Juro total: 10.000 × 5% × 12 = RD$ 6.000\n• Total a pagar: 16.000\n• Parcela mensal: 16.000 / 12 = RD$ 1.333,33\n\nA mesma parcela durante os 12 meses.' },
  'amort.fixed.label':    { es: 'Amortizable', en: 'Amortizing', pt: 'Amortizável' },
  'amort.fixed.short':    { es: 'Método francés/bancario. Interés sobre saldo, cuota fija. Usado por bancos.', en: 'French/bank method. Interest on balance, fixed installment. Used by banks.', pt: 'Método francês/bancário. Juros sobre o saldo, parcela fixa. Usado por bancos.' },
  'amort.fixed.long':     { es: 'Conocido como "amortización francesa" o "sistema bancario". La cuota es fija pero internamente cambia la proporción: al inicio se paga más interés y menos capital; al final se paga más capital y menos interés. Es lo que usan los bancos en préstamos hipotecarios y vehículos.', en: 'Known as "French amortization" or "bank system". The installment is fixed but the internal proportion changes: at the start you pay more interest and less principal; at the end more principal and less interest. It is what banks use for mortgages and car loans.', pt: 'Conhecido como "amortização francesa" ou "sistema bancário". A parcela é fixa, mas a proporção interna muda: no início paga-se mais juros e menos capital; no final, mais capital e menos juros. É o que os bancos usam em financiamentos imobiliários e de veículos.' },
  'amort.fixed.example':  { es: 'Préstamo RD$ 10,000 al 5% mensual a 12 meses:\n• Cuota mensual fija: ~RD$ 1,128.25\n• Cuota 1: interés RD$ 500.00 + capital RD$ 628.25\n• Cuota 6: interés RD$ 296.97 + capital RD$ 831.28\n• Cuota 12: interés RD$ 53.72 + capital RD$ 1,074.53\n\nTotal pagado: RD$ 13,539 (interés total RD$ 3,539).', en: 'Loan RD$ 10,000 at 5% monthly for 12 months:\n• Fixed monthly installment: ~RD$ 1,128.25\n• Installment 1: interest RD$ 500.00 + principal RD$ 628.25\n• Installment 6: interest RD$ 296.97 + principal RD$ 831.28\n• Installment 12: interest RD$ 53.72 + principal RD$ 1,074.53\n\nTotal paid: RD$ 13,539 (total interest RD$ 3,539).', pt: 'Empréstimo RD$ 10.000 a 5% mensal em 12 meses:\n• Parcela mensal fixa: ~RD$ 1.128,25\n• Parcela 1: juros RD$ 500,00 + capital RD$ 628,25\n• Parcela 6: juros RD$ 296,97 + capital RD$ 831,28\n• Parcela 12: juros RD$ 53,72 + capital RD$ 1.074,53\n\nTotal pago: RD$ 13.539 (juro total RD$ 3.539).' },
  'amort.io.label':       { es: 'Solo Interés', en: 'Interest Only', pt: 'Somente Juros' },
  'amort.io.short':       { es: 'Pagas solo intereses mensuales. El capital se paga completo al final.', en: 'You pay only monthly interest. The principal is paid in full at the end.', pt: 'Você paga apenas juros mensais. O capital é pago integralmente no final.' },
  'amort.io.long':        { es: 'También conocido como "préstamo con bullet" o "Réditos". Durante el plazo el cliente solo paga el interés cada mes. El capital prestado se devuelve completo en la última cuota. Útil para préstamos puente o cuando el cliente espera un ingreso grande al final.', en: 'Also known as a "bullet loan". During the term the client only pays interest each month. The borrowed principal is returned in full in the last installment. Useful for bridge loans or when the client expects a large income at the end.', pt: 'Também conhecido como "empréstimo bullet". Durante o prazo o cliente paga apenas os juros a cada mês. O capital emprestado é devolvido integralmente na última parcela. Útil para empréstimos-ponte ou quando o cliente espera uma renda grande no final.' },
  'amort.io.example':     { es: 'Préstamo RD$ 10,000 al 5% mensual a 12 meses:\n• Cuotas 1 a 11: solo RD$ 500.00 (interés mensual)\n• Cuota 12: RD$ 500.00 (interés) + RD$ 10,000 (capital) = RD$ 10,500\n\nTotal pagado: RD$ 16,000 (interés total RD$ 6,000).', en: 'Loan RD$ 10,000 at 5% monthly for 12 months:\n• Installments 1 to 11: only RD$ 500.00 (monthly interest)\n• Installment 12: RD$ 500.00 (interest) + RD$ 10,000 (principal) = RD$ 10,500\n\nTotal paid: RD$ 16,000 (total interest RD$ 6,000).', pt: 'Empréstimo RD$ 10.000 a 5% mensal em 12 meses:\n• Parcelas 1 a 11: apenas RD$ 500,00 (juro mensal)\n• Parcela 12: RD$ 500,00 (juros) + RD$ 10.000 (capital) = RD$ 10.500\n\nTotal pago: RD$ 16.000 (juro total RD$ 6.000).' },
  'amort.modal_title':    { es: 'Tipos de Amortización', en: 'Amortization Types', pt: 'Tipos de Amortização' },
  'amort.modal_subtitle': { es: 'Cómo se calcula la cuota según el método elegido', en: 'How the installment is calculated by the chosen method', pt: 'Como a parcela é calculada conforme o método escolhido' },
  'amort.close':          { es: 'Cerrar', en: 'Close', pt: 'Fechar' },
  'amort.selected':       { es: 'Seleccionado', en: 'Selected', pt: 'Selecionado' },
  'amort.example':        { es: 'Ejemplo', en: 'Example', pt: 'Exemplo' },
  'amort.modal_note':     { es: 'Los cálculos usan tasa mensual. Si trabajas con tasas semanales o quincenales, el sistema las convierte automáticamente.', en: 'Calculations use the monthly rate. If you work with weekly or biweekly rates, the system converts them automatically.', pt: 'Os cálculos usam a taxa mensal. Se você trabalha com taxas semanais ou quinzenais, o sistema as converte automaticamente.' },
  'amort.understood':     { es: 'Entendido', en: 'Got it', pt: 'Entendido' },

